const FEDB = {"Squat":{"i":["Bodyweight_Squat/0.jpg","Bodyweight_Squat/1.jpg"],"t":"Stand with your feet shoulder width apart. You can place your hands behind your head. This will be your starting position. Begin the movement by flexing your knees and hips, sitting back with your hips. Continue down to full depth if you are able,and quickly reverse the motion until you return to the starting position. As you squat, keep your head and chest up and push your knees out."},"Goblet Squat":{"i":["Goblet_Squat/0.jpg","Goblet_Squat/1.jpg"],"t":"Stand holding a light kettlebell by the horns close to your chest. This will be your starting position. Squat down between your legs until your hamstrings are on your calves. Keep your chest and head up and your back straight. At the bottom position, pause and use your elbows to push your knees out. Return to the starting position, and repeat for 10-20 repetitions."},"Barbell Back Squat":{"i":["Barbell_Squat/0.jpg","Barbell_Squat/1.jpg"],"t":"This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack to just below shoulder level. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it. Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso. Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times and also maintain a straight back. This will be your starting position. (Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances discussed in the foot stances section). Begin to slowly lower the bar by bending the knees and hips as you maintain a straight posture with the head up. Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees. Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly. Begin to raise the bar as you exhale by pushing the floor with the heel of your foot as you straighten the legs again and go back to the starting position. Repeat for the recommended amount of repetitions."},"Bulgarian Split Squat":{"i":["Split_Squats/0.jpg","Split_Squats/1.jpg"],"t":"Being in a standing position. Jump into a split leg position, with one leg forward and one leg back, flexing the knees and lowering your hips slightly as you do so. As you descend, immediately reverse direction, standing back up and jumping, reversing the position of your legs. Repeat 5-10 times on each leg."},"Jump Squat":{"i":["Freehand_Jump_Squat/0.jpg","Freehand_Jump_Squat/1.jpg"],"t":"Cross your arms over your chest. With your head up and your back straight, position your feet at shoulder width. Keeping your back straight and chest up, squat down as you inhale until your upper thighs are parallel, or lower, to the floor. Now pressing mainly with the ball of your feet, jump straight up in the air as high as possible, using the thighs like springs. Exhale during this portion of the movement. When you touch the floor again, immediately squat down and jump again. Repeat for the recommended amount of repetitions."},"Lunge":{"i":["Dumbbell_Lunges/0.jpg","Dumbbell_Lunges/1.jpg"],"t":"Stand with your torso upright holding two dumbbells in your hands by your sides. This will be your starting position. Step forward with your right leg around 2 feet or so from the foot being left stationary behind and lower your upper body down, while keeping the torso upright and maintaining balance. Inhale as you go down. Note: As in the other exercises, do not allow your knee to go forward beyond your toes as you come down, as this will put undue stress on the knee joint. Make sure that you keep your front shin perpendicular to the ground. Using mainly the heel of your foot, push up and go back to the starting position as you exhale. Repeat the movement for the recommended amount of repetitions and then perform with the left leg."},"Reverse Lunge":{"i":["Dumbbell_Rear_Lunge/0.jpg","Dumbbell_Rear_Lunge/1.jpg"],"t":"Stand with your torso upright holding two dumbbells in your hands by your sides. This will be your starting position. Step backward with your right leg around two feet or so from the left foot and lower your upper body down, while keeping the torso upright and maintaining balance. Inhale as you go down. Tip: As in the other exercises, do not allow your knee to go forward beyond your toes as you come down, as this will put undue stress on the knee joint. Make sure that you keep your front shin perpendicular to the ground. Keep the torso upright during the lunge; flexible hip flexors are important. A long lunge emphasizes the Gluteus Maximus; a short lunge emphasizes Quadriceps. Push up and go back to the starting position as you exhale. Tip: Use the ball of your feet to push in order to accentuate the quadriceps. To focus on the glutes, press with your heels. Now repeat with the opposite leg."},"Walking Lunge":{"i":["Bodyweight_Walking_Lunge/0.jpg","Bodyweight_Walking_Lunge/1.jpg"],"t":"Begin standing with your feet shoulder width apart and your hands on your hips. Step forward with one leg, flexing the knees to drop your hips. Descend until your rear knee nearly touches the ground. Your posture should remain upright, and your front knee should stay above the front foot. Drive through the heel of your lead foot and extend both knees to raise yourself back up. Step forward with your rear foot, repeating the lunge on the opposite leg."},"Step Up":{"i":["Dumbbell_Step_Ups/0.jpg","Dumbbell_Step_Ups/1.jpg"],"t":"Stand up straight while holding a dumbbell on each hand (palms facing the side of your legs). Place the right foot on the elevated platform. Step on the platform by extending the hip and the knee of your right leg. Use the heel mainly to lift the rest of your body up and place the foot of the left leg on the platform as well. Breathe out as you execute the force required to come up. Step down with the left leg by flexing the hip and knee of the right leg as you inhale. Return to the original standing position by placing the right foot of to next to the left foot on the initial position. Repeat with the right leg for the recommended amount of repetitions and then perform with the left leg."},"Deadlift":{"i":["Barbell_Deadlift/0.jpg","Barbell_Deadlift/1.jpg"],"t":"Stand in front of a loaded barbell. While keeping the back as straight as possible, bend your knees, bend forward and grasp the bar using a medium (shoulder width) overhand grip. This will be the starting position of the exercise. Tip: If it is difficult to hold on to the bar with this grip, alternate your grip or use wrist straps. While holding the bar, start the lift by pushing with your legs while simultaneously getting your torso to the upright position as you breathe out. In the upright position, stick your chest out and contract the back by bringing the shoulder blades back. Think of how the soldiers in the military look when they are in standing in attention. Go back to the starting position by bending at the knees while simultaneously leaning the torso forward at the waist while keeping the back straight. When the weights on the bar touch the floor you are back at the starting position and ready to perform another repetition. Perform the amount of repetitions prescribed in the program."},"Romanian Deadlift":{"i":["Romanian_Deadlift/0.jpg","Romanian_Deadlift/1.jpg"],"t":"Put a barbell in front of you on the ground and grab it using a pronated (palms facing down) grip that a little wider than shoulder width. Tip: Depending on the weight used, you may need wrist wraps to perform the exercise and also a raised platform in order to allow for better range of motion. Bend the knees slightly and keep the shins vertical, hips back and back straight. This will be your starting position. Keeping your back and arms completely straight at all times, use your hips to lift the bar as you exhale. Tip: The movement should not be fast but steady and under control. Once you are standing completely straight up, lower the bar by pushing the hips back, only slightly bending the knees, unlike when squatting. Tip: Take a deep breath at the start of the movement and keep your chest up. Hold your breath as you lower and exhale as you complete the movement. Repeat for the recommended amount of repetitions."},"Kettlebell Swing":{"i":["One-Arm_Kettlebell_Swings/0.jpg","One-Arm_Kettlebell_Swings/1.jpg"],"t":""},"Glute Bridge":{"i":["Butt_Lift_Bridge/0.jpg","Butt_Lift_Bridge/1.jpg"],"t":"Lie flat on the floor on your back with the hands by your side and your knees bent. Your feet should be placed around shoulder width. This will be your starting position. Pushing mainly with your heels, lift your hips off the floor while keeping your back straight. Breathe out as you perform this part of the motion and hold at the top for a second. Slowly go back to the starting position as you breathe in."},"Hip Raise":{"i":["Butt_Lift_Bridge/0.jpg","Butt_Lift_Bridge/1.jpg"],"t":"Lie flat on the floor on your back with the hands by your side and your knees bent. Your feet should be placed around shoulder width. This will be your starting position. Pushing mainly with your heels, lift your hips off the floor while keeping your back straight. Breathe out as you perform this part of the motion and hold at the top for a second. Slowly go back to the starting position as you breathe in."},"Push Up":{"i":["Pushups/0.jpg","Pushups/1.jpg"],"t":"Lie on the floor face down and place your hands about 36 inches apart while holding your torso up at arms length. Next, lower yourself downward until your chest almost touches the floor as you inhale. Now breathe out and press your upper body back up to the starting position while squeezing your chest. After a brief pause at the top contracted position, you can begin to lower yourself downward again for as many repetitions as needed."},"Incline Push Up":{"i":["Incline_Push-Up/0.jpg","Incline_Push-Up/1.jpg"],"t":"Stand facing bench or sturdy elevated platform. Place hands on edge of bench or platform, slightly wider than shoulder width. Position forefoot back from bench or platform with arms and body straight. Arms should be perpendicular to body. Keeping body straight, lower chest to edge of box or platform by bending arms. Push body up until arms are extended. Repeat."},"Bench Press":{"i":["Barbell_Bench_Press_-_Medium_Grip/0.jpg","Barbell_Bench_Press_-_Medium_Grip/1.jpg"],"t":"Lie back on a flat bench. Using a medium width grip (a grip that creates a 90-degree angle in the middle of the movement between the forearms and the upper arms), lift the bar from the rack and hold it straight over you with your arms locked. This will be your starting position. From the starting position, breathe in and begin coming down slowly until the bar touches your middle chest. After a brief pause, push the bar back to the starting position as you breathe out. Focus on pushing the bar using your chest muscles. Lock your arms and squeeze your chest in the contracted position at the top of the motion, hold for a second and then start coming down slowly again. Tip: Ideally, lowering the weight should take about twice as long as raising it. Repeat the movement for the prescribed amount of repetitions. When you are done, place the bar back in the rack."},"Dumbbell Bench Press":{"i":["Dumbbell_Bench_Press/0.jpg","Dumbbell_Bench_Press/1.jpg"],"t":"Lie down on a flat bench with a dumbbell in each hand resting on top of your thighs. The palms of your hands will be facing each other. Then, using your thighs to help raise the dumbbells up, lift the dumbbells one at a time so that you can hold them in front of you at shoulder width. Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. The dumbbells should be just to the sides of your chest, with your upper arm and forearm creating a 90 degree angle. Be sure to maintain full control of the dumbbells at all times. This will be your starting position. Then, as you breathe out, use your chest to push the dumbbells up. Lock your arms at the top of the lift and squeeze your chest, hold for a second and then begin coming down slowly. Tip: Ideally, lowering the weight should take about twice as long as raising it. Repeat the movement for the prescribed amount of repetitions of your training program."},"Chest Fly":{"i":["Dumbbell_Flyes/0.jpg","Dumbbell_Flyes/1.jpg"],"t":"Lie down on a flat bench with a dumbbell on each hand resting on top of your thighs. The palms of your hand will be facing each other. Then using your thighs to help raise the dumbbells, lift the dumbbells one at a time so you can hold them in front of you at shoulder width with the palms of your hands facing each other. Raise the dumbbells up like you're pressing them, but stop and hold just before you lock out. This will be your starting position. With a slight bend on your elbows in order to prevent stress at the biceps tendon, lower your arms out at both sides in a wide arc until you feel a stretch on your chest. Breathe in as you perform this portion of the movement. Tip: Keep in mind that throughout the movement, the arms should remain stationary; the movement should only occur at the shoulder joint. Return your arms back to the starting position as you squeeze your chest muscles and breathe out. Tip: Make sure to use the same arc of motion used to lower the weights. Hold for a second at the contracted position and repeat the movement for the prescribed amount of repetitions."},"Pull Up":{"i":["Pullups/0.jpg","Pullups/1.jpg"],"t":"Grab the pull-up bar with the palms facing forward using the prescribed grip. Note on grips: For a wide grip, your hands need to be spaced out at a distance wider than your shoulder width. For a medium grip, your hands need to be spaced out at a distance equal to your shoulder width and for a close grip at a distance smaller than your shoulder width. As you have both arms extended in front of you holding the bar at the chosen grip width, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position. Pull your torso up until the bar touches your upper chest by drawing the shoulders and the upper arms down and back. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar. After a second on the contracted position, start to inhale and slowly lower your torso back to the starting position when your arms are fully extended and the lats are fully stretched. Repeat this motion for the prescribed amount of repetitions."},"Chin Up":{"i":["Chin-Up/0.jpg","Chin-Up/1.jpg"],"t":"Grab the pull-up bar with the palms facing your torso and a grip closer than the shoulder width. As you have both arms extended in front of you holding the bar at the chosen grip width, keep your torso as straight as possible while creating a curvature on your lower back and sticking your chest out. This is your starting position. Tip: Keeping the torso as straight as possible maximizes biceps stimulation while minimizing back involvement. As you breathe out, pull your torso up until your head is around the level of the pull-up bar. Concentrate on using the biceps muscles in order to perform the movement. Keep the elbows close to your body. Tip: The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar. After a second of squeezing the biceps in the contracted position, slowly lower your torso back to the starting position; when your arms are fully extended. Breathe in as you perform this portion of the movement. Repeat this motion for the prescribed amount of repetitions."},"Bent Over Row":{"i":["Bent_Over_Barbell_Row/0.jpg","Bent_Over_Barbell_Row/1.jpg"],"t":"Holding a barbell with a pronated grip (palms facing down), bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up. The barbell should hang directly in front of you as your arms hang perpendicular to the floor and your torso. This is your starting position. Now, while keeping the torso stationary, breathe out and lift the barbell to you. Keep the elbows close to the body and only use the forearms to hold the weight. At the top contracted position, squeeze the back muscles and hold for a brief pause. Then inhale and slowly lower the barbell back to the starting position. Repeat for the recommended amount of repetitions."},"Single Arm Row":{"i":["One-Arm_Dumbbell_Row/0.jpg","One-Arm_Dumbbell_Row/1.jpg"],"t":"Choose a flat bench and place a dumbbell on each side of it. Place the right leg on top of the end of the bench, bend your torso forward from the waist until your upper body is parallel to the floor, and place your right hand on the other end of the bench for support. Use the left hand to pick up the dumbbell on the floor and hold the weight while keeping your lower back straight. The palm of the hand should be facing your torso. This will be your starting position. Pull the resistance straight up to the side of your chest, keeping your upper arm close to your side and keeping the torso stationary. Breathe out as you perform this step. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. Also, make sure that the force is performed with the back muscles and not the arms. Finally, the upper torso should remain stationary and only the arms should move. The forearms should do no other work except for holding the dumbbell; therefore do not try to pull the dumbbell up using the forearms. Lower the resistance straight down to the starting position. Breathe in as you perform this step. Repeat the movement for the specified amount of repetitions. Switch sides and repeat again with the other arm."},"Lat Pulldown":{"i":["Wide-Grip_Lat_Pulldown/0.jpg","Wide-Grip_Lat_Pulldown/1.jpg"],"t":"Sit down on a pull-down machine with a wide bar attached to the top pulley. Make sure that you adjust the knee pad of the machine to fit your height. These pads will prevent your body from being raised by the resistance attached to the bar. Grab the bar with the palms facing forward using the prescribed grip. Note on grips: For a wide grip, your hands need to be spaced out at a distance wider than shoulder width. For a medium grip, your hands need to be spaced out at a distance equal to your shoulder width and for a close grip at a distance smaller than your shoulder width. As you have both arms extended in front of you holding the bar at the chosen grip width, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position. As you breathe out, bring the bar down until it touches your upper chest by drawing the shoulders and the upper arms down and back. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary and only the arms should move. The forearms should do no other work except for holding the bar; therefore do not try to pull down the bar using the forearms. After a second at the contracted position squeezing your shoulder blades together, slowly raise the bar back to the starting position when your arms are fully extended and the lats are fully stretched. Inhale during this portion of the movement. Repeat this motion for the prescribed amount of repetitions."},"Face Pull":{"i":["Face_Pull/0.jpg","Face_Pull/1.jpg"],"t":"Facing a high pulley with a rope or dual handles attached, pull the weight directly towards your face, separating your hands as you do so. Keep your upper arms parallel to the ground."},"Overhead Press":{"i":["Standing_Military_Press/0.jpg","Standing_Military_Press/1.jpg"],"t":"Start by placing a barbell that is about chest high on a squat rack. Once you have selected the weights, grab the barbell using a pronated (palms facing forward) grip. Make sure to grip the bar wider than shoulder width apart from each other. Slightly bend the knees and place the barbell on your collar bone. Lift the barbell up keeping it lying on your chest. Take a step back and position your feet shoulder width apart from each other. Once you pick up the barbell with the correct grip length, lift the bar up over your head by locking your arms. Hold at about shoulder level and slightly in front of your head. This is your starting position. Lower the bar down to the collarbone slowly as you inhale. Lift the bar back up to the starting position as you exhale. Repeat for the recommended amount of repetitions."},"Arnold Press":{"i":["Arnold_Dumbbell_Press/0.jpg","Arnold_Dumbbell_Press/1.jpg"],"t":"Sit on an exercise bench with back support and hold two dumbbells in front of you at about upper chest level with your palms facing your body and your elbows bent. Tip: Your arms should be next to your torso. The starting position should look like the contracted portion of a dumbbell curl. Now to perform the movement, raise the dumbbells as you rotate the palms of your hands until they are facing forward. Continue lifting the dumbbells until your arms are extended above you in straight arm position. Breathe out as you perform this portion of the movement. After a second pause at the top, begin to lower the dumbbells to the original position by rotating the palms of your hands towards you. Tip: The left arm will be rotated in a counter clockwise manner while the right one will be rotated clockwise. Breathe in as you perform this portion of the movement. Repeat for the recommended amount of repetitions."},"Lateral Raise":{"i":["Side_Lateral_Raise/0.jpg","Side_Lateral_Raise/1.jpg"],"t":"Pick a couple of dumbbells and stand with a straight torso and the dumbbells by your side at arms length with the palms of the hand facing you. This will be your starting position. While maintaining the torso in a stationary position (no swinging), lift the dumbbells to your side with a slight bend on the elbow and the hands slightly tilted forward as if pouring water in a glass. Continue to go up until you arms are parallel to the floor. Exhale as you execute this movement and pause for a second at the top. Lower the dumbbells back down slowly to the starting position as you inhale. Repeat for the recommended amount of repetitions."},"Front Raise":{"i":["Front_Dumbbell_Raise/0.jpg","Front_Dumbbell_Raise/1.jpg"],"t":"Pick a couple of dumbbells and stand with a straight torso and the dumbbells on front of your thighs at arms length with the palms of the hand facing your thighs. This will be your starting position. While maintaining the torso stationary (no swinging), lift the left dumbbell to the front with a slight bend on the elbow and the palms of the hands always facing down. Continue to go up until you arm is slightly above parallel to the floor. Exhale as you execute this portion of the movement and pause for a second at the top. Inhale after the second pause. Now lower the dumbbell back down slowly to the starting position as you simultaneously lift the right dumbbell. Continue alternating in this fashion until all of the recommended amount of repetitions have been performed for each arm."},"Shrug":{"i":["Barbell_Shrug/0.jpg","Barbell_Shrug/1.jpg"],"t":"Stand up straight with your feet at shoulder width as you hold a barbell with both hands in front of you using a pronated grip (palms facing the thighs). Tip: Your hands should be a little wider than shoulder width apart. You can use wrist wraps for this exercise for a better grip. This will be your starting position. Raise your shoulders up as far as you can go as you breathe out and hold the contraction for a second. Tip: Refrain from trying to lift the barbell by using your biceps. Slowly return to the starting position as you breathe in. Repeat for the recommended amount of repetitions."},"Biceps Curl":{"i":["Dumbbell_Bicep_Curl/0.jpg","Dumbbell_Bicep_Curl/1.jpg"],"t":"Stand up straight with a dumbbell in each hand at arm's length. Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. This will be your starting position. Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps. Then, inhale and slowly begin to lower the dumbbells back to the starting position. Repeat for the recommended amount of repetitions."},"Hammer Curl":{"i":["Hammer_Curls/0.jpg","Hammer_Curls/1.jpg"],"t":"Stand up with your torso upright and a dumbbell on each hand being held at arms length. The elbows should be close to the torso. The palms of the hands should be facing your torso. This will be your starting position. Now, while holding your upper arm stationary, exhale and curl the weight forward while contracting the biceps. Continue to raise the weight until the biceps are fully contracted and the dumbbell is at shoulder level. Hold the contracted position for a brief moment as you squeeze the biceps. Tip: Focus on keeping the elbow stationary and only moving your forearm. After the brief pause, inhale and slowly begin the lower the dumbbells back down to the starting position. Repeat for the recommended amount of repetitions."},"Triceps Extension":{"i":["Standing_Dumbbell_Triceps_Extension/0.jpg","Standing_Dumbbell_Triceps_Extension/1.jpg"],"t":"To begin, stand up with a dumbbell held by both hands. Your feet should be about shoulder width apart from each other. Slowly use both hands to grab the dumbbell and lift it over your head until both arms are fully extended. The resistance should be resting in the palms of your hands with your thumbs around it. The palm of the hands should be facing up towards the ceiling. This will be your starting position. Keeping your upper arms close to your head with elbows in and perpendicular to the floor, lower the resistance in a semicircular motion behind your head until your forearms touch your biceps. Tip: The upper arms should remain stationary and only the forearms should move. Breathe in as you perform this step. Go back to the starting position by using the triceps to raise the dumbbell. Breathe out as you perform this step. Repeat for the recommended amount of repetitions."},"Triceps Dip":{"i":["Dips_-_Triceps_Version/0.jpg","Dips_-_Triceps_Version/1.jpg"],"t":"To get into the starting position, hold your body at arm's length with your arms nearly locked above the bars. Now, inhale and slowly lower yourself downward. Your torso should remain upright and your elbows should stay close to your body. This helps to better focus on tricep involvement. Lower yourself until there is a 90 degree angle formed between the upper arm and forearm. Then, exhale and push your torso back up using your triceps to bring your body back to the starting position. Repeat the movement for the prescribed amount of repetitions."},"Plank":{"i":["Plank/0.jpg","Plank/1.jpg"],"t":"Get into a prone position on the floor, supporting your weight on your toes and your forearms. Your arms are bent and directly below the shoulder. Keep your body straight at all times, and hold this position as long as possible. To increase difficulty, an arm or leg can be raised."},"Side Plank":{"i":["Side_Bridge/0.jpg","Side_Bridge/1.jpg"],"t":""},"Crunch":{"i":["Crunches/0.jpg","Crunches/1.jpg"],"t":"Lie flat on your back with your feet flat on the ground, or resting on a bench with your knees bent at a 90 degree angle. If you are resting your feet on a bench, place them three to four inches apart and point your toes inward so they touch. Now place your hands lightly on either side of your head keeping your elbows in. Tip: Don't lock your fingers behind your head. While pushing the small of your back down in the floor to better isolate your abdominal muscles, begin to roll your shoulders off the floor. Continue to push down as hard as you can with your lower back as you contract your abdominals and exhale. Your shoulders should come up off the floor only about four inches, and your lower back should remain on the floor. At the top of the movement, contract your abdominals hard and keep the contraction for a second. Tip: Focus on slow, controlled movement - don't cheat yourself by using momentum. After the one second contraction, begin to come down slowly again to the starting position as you inhale. Repeat for the recommended amount of repetitions."},"Bicycle Crunch":{"i":["Air_Bike/0.jpg","Air_Bike/1.jpg"],"t":"Lie flat on the floor with your lower back pressed to the ground. For this exercise, you will need to put your hands beside your head. Be careful however to not strain with the neck as you perform it. Now lift your shoulders into the crunch position. Bring knees up to where they are perpendicular to the floor, with your lower legs parallel to the floor. This will be your starting position. Now simultaneously, slowly go through a cycle pedal motion kicking forward with the right leg and bringing in the knee of the left leg. Bring your right elbow close to your left knee by crunching to the side, as you breathe out. Go back to the initial position as you breathe in. Crunch to the opposite side as you cycle your legs and bring closer your left elbow to your right knee and exhale. Continue alternating in this manner until all of the recommended repetitions for each side have been completed."},"Russian Twist":{"i":["Russian_Twist/0.jpg","Russian_Twist/1.jpg"],"t":"Lie down on the floor placing your feet either under something that will not move or by having a partner hold them. Your legs should be bent at the knees. Elevate your upper body so that it creates an imaginary V-shape with your thighs. Your arms should be fully extended in front of you perpendicular to your torso and with the hands clasped. This is the starting position. Twist your torso to the right side until your arms are parallel with the floor while breathing out. Hold the contraction for a second and move back to the starting position while breathing out. Now move to the opposite side performing the same techniques you applied to the right side. Repeat for the recommended amount of repetitions."},"Mountain Climber":{"i":["Mountain_Climbers/0.jpg","Mountain_Climbers/1.jpg"],"t":"Begin in a pushup position, with your weight supported by your hands and toes. Flexing the knee and hip, bring one leg until the knee is approximately under the hip. This will be your starting position. Explosively reverse the positions of your legs, extending the bent leg until the leg is straight and supported by the toe, and bringing the other foot up with the hip and knee flexed. Repeat in an alternating fashion for 20-30 seconds."},"Dead Bug":{"i":["Dead_Bug/0.jpg","Dead_Bug/1.jpg"],"t":"Begin lying on your back with your hands extended above you toward the ceiling. Bring your feet, knees, and hips up to 90 degrees. Exhale hard to bring your ribcage down and flatten your back onto the floor, rotating your pelvis up and squeezing your glutes. Hold this position throughout the movement. This will be your starting position. Initiate the exercise by extending one leg, straightening the knee and hip to bring the leg just above the ground. Maintain the position of your lumbar and pelvis as you perform the movement, as your back is going to want to arch. Stay tight and return the working leg to the starting position. Repeat on the opposite side, alternating until the set is complete."},"Leg Raise":{"i":["Flat_Bench_Lying_Leg_Raise/0.jpg","Flat_Bench_Lying_Leg_Raise/1.jpg"],"t":"Lie with your back flat on a bench and your legs extended in front of you off the end. Place your hands either under your glutes with your palms down or by the sides holding on to the bench. This will be your starting position. As you keep your legs extended, straight as possible with your knees slightly bent but locked raise your legs until they make a 90-degree angle with the floor. Exhale as you perform this portion of the movement and hold the contraction at the top for a second. Now, as you inhale, slowly lower your legs back down to the starting position."},"Jump Rope":{"i":["Rope_Jumping/0.jpg","Rope_Jumping/1.jpg"],"t":"Hold an end of the rope in each hand. Position the rope behind you on the ground. Raise your arms up and turn the rope over your head bringing it down in front of you. When it reaches the ground, jump over it. Find a good turning pace that can be maintained. Different speeds and techniques can be used to introduce variation. Rope jumping is exciting, challenges your coordination, and requires a lot of energy. A 150 lb person will burn about 350 calories jumping rope for 30 minutes, compared to over 450 calories running."},"Row Machine":{"i":["Rowing_Stationary/0.jpg","Rowing_Stationary/1.jpg"],"t":"To begin, seat yourself on the rower. Make sure that your heels are resting comfortably against the base of the foot pedals and that the straps are secured. Select the program that you wish to use, if applicable. Sit up straight and bend forward at the hips. There are three phases of movement when using a rower. The first phase is when you come forward on the rower. Your knees are bent and against your chest. Your upper body is leaning slightly forward while still maintaining good posture. Next, push against the foot pedals and extend your legs while bringing your hands to your upper abdominal area, squeezing your shoulders back as you do so. To avoid straining your back, use primarily your leg and hip muscles. The recovery phase simply involves straightening your arms, bending the knees, and bringing your body forward again as you transition back into the first phase."},"Stationary Bike":{"i":["Bicycling_Stationary/0.jpg","Bicycling_Stationary/1.jpg"],"t":"To begin, seat yourself on the bike and adjust the seat to your height. Select the desired option from the menu. You may have to start pedaling to turn it on. You can use the manual setting, or you can select a program to use. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. The level of resistance can be changed throughout the workout. The handles can be used to monitor your heart rate to help you stay at an appropriate intensity."},"Child's Pose":{"i":["Childs_Pose/0.jpg","Childs_Pose/1.jpg"],"t":"Get on your hands and knees, walk your hands in front of you. Lower your buttocks down to sit on your heels. Let your arms drag along the floor as you sit back to stretch your entire spine. Once you settle onto your heels, bring your hands next to your feet and relax. \"breathe\" into your back. Rest your forehead on the floor. Avoid this position if you have knee problems."},"Cat Cow":{"i":["Cat_Stretch/0.jpg","Cat_Stretch/1.jpg"],"t":"Position yourself on the floor on your hands and knees. Pull your belly in and round your spine, lower back, shoulders, and neck, letting your head drop. Hold for 15 seconds."},"Bridge Pose":{"i":["Pelvic_Tilt_Into_Bridge/0.jpg","Pelvic_Tilt_Into_Bridge/1.jpg"],"t":"Lie down with your feet on the floor, heels directly under your knees. Lift only your tailbone to the ceiling to stretch your lower back. (Don't lift the entire spine yet.) Pull in your stomach. To go into a bridge, lift the entire spine except the neck."},"Swimming":{"i":["Superman/0.jpg","Superman/1.jpg"],"t":"To begin, lie straight and face down on the floor or exercise mat. Your arms should be fully extended in front of you. This is the starting position. Simultaneously raise your arms, legs, and chest off of the floor and hold this contraction for 2 seconds. Tip: Squeeze your lower back to get the best results from this exercise. Remember to exhale during this movement. Note: When holding the contracted position, you should look like superman when he is flying. Slowly begin to lower your arms, legs and chest back down to the starting position while inhaling. Repeat for the recommended amount of repetitions prescribed in your program."},"Scissor Kick":{"i":["Scissor_Kick/0.jpg","Scissor_Kick/1.jpg"],"t":"To begin, lie down with your back pressed against the floor or on an exercise mat (optional). Your arms should be fully extended to the sides with your palms facing down. Note: The arms should be stationary the entire time. With a slight bend at the knees, lift your legs up so that your heels are about 6 inches off the ground. This is the starting position. Now lift your left leg up to about a 45 degree angle while your right leg is lowered until the heel is about 2-3 inches from the ground. Switch movements by raising your right leg up and lowering your left leg. Remember to breathe while performing this exercise. Repeat for the recommended amount of repetitions."},"Hamstring Stretch":{"i":["Standing_Hamstring_and_Calf_Stretch/0.jpg","Standing_Hamstring_and_Calf_Stretch/1.jpg"],"t":"Being by looping a belt, band, or rope around one foot. While standing, place that foot forward. Bend your back leg, while keeping the front one straight. Now raise the toes of your front foot off of the ground and lean forward. Using the belt, pull on the top of the foot to increase the stretch in the calf. Hold for 10-20 seconds and repeat with the other foot."},"Hip Flexor Stretch":{"i":["Kneeling_Hip_Flexor/0.jpg","Kneeling_Hip_Flexor/1.jpg"],"t":"Kneel on a mat and bring your right knee up so the bottom of your foot is on the floor and extend your left leg out behind you so the top of your foot is on the floor. Shift your weight forward until you feel a stretch in your hip. Hold for 15 seconds, then repeat for your other side."},"Lateral Pillar Bridge":{"i":["Side_Bridge/0.jpg","Side_Bridge/1.jpg"],"t":""}};
const NYTDESC = {
 "Plank with Arm Lift":"Hold a straight-arm plank, then lift one arm out in front of you, lower it, and lift the other. Keep your hips level and alternate steadily.",
 "Side Plank":"Lie on one side, prop yourself on your forearm with elbow under shoulder, and lift your hips so your body forms a straight line. Hold, then switch sides.",
 "Kettlebell Swing":"With feet shoulder-width apart, hinge at the hips and swing the kettlebell back between your legs, then drive your hips forward to swing it to chest height. Repeat fluidly.",
 "Jumping Jacks":"Stand tall, then jump your feet out wide while swinging your arms overhead. Jump back to the start and repeat at a steady rhythm.",
 "Wall Squat":"Lean your back flat against a wall and slide down until your knees are bent about 90 degrees, as if sitting on an invisible chair. Hold.",
 "High Knees":"Run in place, driving each knee up toward hip height. Stay light on your feet and pump your arms.",
 "Burpee":"From standing, drop your hands to the floor, jump your feet back into a plank, return them under you, and jump up. Repeat.",
 "Push Up with Rotation":"Do a push-up, then rotate your body to one side, raising that arm toward the ceiling into a side-plank position. Return, repeat, and alternate sides.",
 "Reverse Lunge with Rotation":"Step one leg far back into a reverse lunge, place your opposite elbow inside the front knee, then rotate your other arm and chest toward the ceiling. Stand and alternate sides.",
 "Push-Up to Row to Burpee":"With hands on dumbbells in a push-up position, do a push-up, row each dumbbell to your ribs, jump the feet in, stand tall, then jump back out. Repeat the sequence.",
 "Single Leg RDL to Curl to Press":"Balancing on one leg with dumbbells, hinge forward extending the free leg back, return upright, curl the weights to your shoulders, then press overhead. Repeat, switching legs halfway.",
 "Lateral Lunge to Overhead Triceps Extension":"Step wide to one side into a lateral lunge holding a dumbbell, return to standing, then extend the weight overhead and lower it behind your head. Alternate sides.",
 "Lateral Pillar Bridge":"Lie on your side, prop up on your forearm, and lift your hips so your body forms a straight line. Reach the top arm toward the ceiling and hold."
};
/* Yoga poses from Yoga API (github.com/alexcumplido/yoga-api, MIT license).
   Images: CC0 / Flaticon (Easy icons by monkik; Yoga icons by dDara, flaticon.com).
   Not in Garmin's catalog, so these export as text-only FIT steps. */
const YOGADB = {
  "Cobra Pose":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483092/yoga-api/35_dytwvz.png",t:"Lie prone with the tops of the feet on the floor and hands under the shoulders. Press into the hands to lift the chest, drawing the shoulders back and down and keeping a slight bend in the elbows. Lengthen through the spine and lift the breastbone without crunching the lower back. Benefits: Strengthens the spine. Stretches the chest, shoulders, and abdomen. Helps relieve stress and fatigue."},
  "Boat":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483071/yoga-api/1_txmirf.png",t:"From a seated position the feet are lifted up so that the thighs are angled about 45-50 degrees relative to the earth. The tailbone is lengthened into the earth and the pubis pulls toward the navel. The shoulder blades are spread across the back and the hands reach around the back of the calves, with legs pulled towards the body. The chin is tipped slightly toward the sternum so that the base of the skull lifts lightly away from the back of the neck. Gaze is forward. Benefits: Strengthens the abdomen, hip flexors, and spine. Stimulates the kidneys, thyroid and prostate glands, and intestines. Helps relieve stress. Improves digestion."},
  "Half Boat":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483073/yoga-api/2_ozh7sv.png",t:"From a seated position the hands are gripped around the back of the legs and the knees are bent in a 90 degree angle. Both legs are pulled in towards the abdomen. The core is engaged to maintain balance on the sits bones (be sure that the back does not round). The front of the torso lengthens between the pubis and top of the sternum as the spine extends in both directions reaching up to the sky and rooting down to the earth. The gaze is forward and Bandhas are engaged. Benefits: Strengthens the abdomen, hip flexors and spine. Stimulates the kidneys, thyroid, prostate glands and intestines. Helps relieve stress. Improves digestion."},
  "Bow":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483072/yoga-api/3_aa0fgk.png",t:"From a prone position with the abdomen on the earth, the hands grip the ankles (but not the tops of the feet) with knees no wider than the width of your hips. The heels are lifted away from the buttocks and at the same time the thighs are lifted away from the earth working opposing forces as the heart center, hips and back open. The gaze is forward. Benefits: Stretches the entire front of the body, ankles, thighs and groins, abdomen and chest, and throat, and deep hip flexors (psoas). Strengthens the back muscles. Improves posture. Stimulates the organs of the abdomen and neck."},
  "Butterfly":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483074/yoga-api/5_i64gif.png",t:"In sitting position, bend both knees and drop the knees to each side, opening the hips. Bring the soles of the feet together and bring the heels as close to the groin as possible, keeping the knees close to the ground. The hands may reach down and grasp and maneuver the feet so that the soles are facing upwards and the heels and little toes are connected. The shoulders should be pulled back and no rounding of the spine. Benefits: Opens the hips and groins. Stretches the shoulders, rib cage and back. Stimulates the abdominal organs, lungs and heart."},
  "Camel":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483075/yoga-api/6_ri1w0e.png",t:"From a kneeling position the knees are hip width apart and the thighs are perpendicular to the earth. The inner thighs are narrowed and rotated slightly inward with the buttocks engaged but not hardened. The tailbone is tucked under but the hips do not puff forward. The shins and tops of the feet are pressed firmly into the earth. The ribcage is open, along with the heart center, but the lower front ribs do not protrude sharply towards the sky. The lower back lifts the ribs away from the pelvis to keep the lower spine as long as possible. The base of the palms are pressed firmly against the soles (or heels) of the feet and the fingers are pointed toward the toes. The arms are extended straight and are turned slightly outward at the shoulder joint so the elbow creases face forward without squeezing the shoulder blades together. The neck is in a relatively neutral position, neither flexed nor extended, or (for the advanced practitioners only) the head drops back. Be careful not to strain your neck and harden your throat. The gaze is either towards the sky or towards the earth, depending upon your flexibility. Benefits: Stretches the entire front of the body, the ankles, thighs and groins, abdomen and chest, and throat. Stretches the deep hip flexors (psoas). Strengthens back muscles. Improves posture. Stimulates the organs of the abdomen and neck."},
  "Chair":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483078/yoga-api/9_ewvoun.png",t:"From a standing position, the feet are together and rooted into the earth with toes actively lifted. The knees are bent and the weight of the body is on the heels of the feet. The pelvis is tucked in and the ribcage is lifted. The neck is a natural extension of the spine. The arms are lifted up toward the sky with the elbows straight and the biceps by the ears. The hands can be together or separated and facing each other with the fingers spread wide. The gaze is forward. Benefits: Strengthens the ankles, thighs, calves, and spine. Stretches shoulders and chest. Stimulates the abdominal organs, diaphragm, and heart. Reduces flat feet. Energizes the entire body."},
  "Corpse":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483078/yoga-api/11_dczyrp.png",t:"The body rests on the earth in a supine position with the arms resting by the side body. The palms are relaxed and open toward the sky. The shoulder blades are pulled back, down and rolled under comfortably, resting evenly on the earth. The legs are extended down and splayed open. The heels are in and the toes flop out. The eyes are closed. Everything is relaxed. The gaze is inward. Benefits: Calms the brain and helps relieve stress and mild depression. Relaxes the body. Reduces headache, fatigue, and insomnia. Helps to lower blood pressure."},
  "Crescent Lunge":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483080/yoga-api/12_pv4p1z.png",t:"From mountain pose, on the inhalation bring the hands up and interlace the fingers together. Exhale, bend to one side, lengthening the opposite of the rib cage and stretch. Benefits: Stretches the rib cage, arms and torso. Tones the oblique muscles."},
  "Crow":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483083/yoga-api/13_hdjxuz.png",t:"From an inverted position, with the hips up and the head down, the arms are bent in a 90-degree angle with the knees resting on the elbows. The palms are firmly rooted into the earth with knuckles pressed firmly into the earth for support. The belly is pulled up and in towards the spine with the ribcage and chin lifted. The weight of the body shifts slightly forward as the toes lift up and off the earth into the full expression of the pose. The gaze is down and slightly forward. Benefits: Strengthens arms and wrists. Stretches the upper back. Strengthens the abdominal muscles. Opens the groin. Tones the abdominal organs."},
  "Dolphin":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483080/yoga-api/14_k9lr9a.png",t:"From Downward-Facing Dog, the forearms are planted onto the earth with the elbows narrow and the palms down in a Sphinx position. The pelvis is tucked. The ribcage lifted. The feet are rooted and the legs are straight with the tailbone in dog tilt. The gaze is down and slightly forward. Benefits: Calms the brain and helps relieve stress and mild depression. Energizes the body. Stretches the shoulders, hamstrings, calves, arches, and hands. Strengthens the arms and legs. Helps relieve the symptoms of menopause. Relieves menstrual discomfort when done with the head supported. Helps prevent osteoporosis. Improves digestion. Relieves headache, insomnia, back pain, and fatigue. Therapeutic for high blood pressure, asthma, flat feet, sciatica, and sinusitis. Warms up the ankles and the toes."},
  "Eagle":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483081/yoga-api/16_g7ueht.png",t:"From a standing position the one thigh is crossed over the other with the toes and/or the ankle hooked behind the lower calf. The weight of the body is balanced on the standing foot. The arms are crossed in front of the torso so that one arm is crossed above the other arm. The top arm is tucked into the elbow crook of the bottom arm. The hands are hooked around each other as well. Once hooked, the elbows lift up and the fingers stretch towards the ceiling. The gaze is soft and forward. Benefits: Strengthens and stretches the ankles and calves. Stretches the thighs, hips, shoulders, and upper back. Improves concentration. Improves sense of balance."},
  "Extended Hand to Toe":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483084/yoga-api/17_l9joyu.png",t:"From mountain pose, lift one foot. Bend forward and catch the toes with the fingers. Place the other hand on the hip to square the hip towards the front. Slowly straighten the knee and the torso and open the leg to one side. Use a strap if necessary. Gaze towards the front or opposite of the extended leg for balance. Benefits: Opens the hips and groins. Stretches the hamstrings, IT bands and legs. Improves balance."},
  "Extended Side Angle":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483083/yoga-api/18_aqufak.png",t:"From warrior II the lower body stays static while the upper body is folded forward at the crease of the hip. One arm is extended toward the front with the bicep by the ear and the fingers spread wide while the other reaches down to the earth on the inside of the thigh. The upper torso and the gaze twist up towards the sky. Benefits: Strengthens and stretches the legs, knees, and ankles. Stretches the groin, spine, waist, chest, lungs, and shoulders. Stimulates abdominal organs. Increases stamina."},
  "Forearm Stand":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483084/yoga-api/19_jadqwc.png",t:"From an inverted position, with the body perpendicular to the earth, the weight of the body is supported on the forearms that are parallel and pressed firmly into the earth. The palms are flat. The knuckles are evenly pressed into the earth. The fingers are spread wide. Both legs reach up toward the sky in a straight line with the pelvis tucked. The ribcage is lifted. The gaze is forward. Benefits: Strengthens arms and shoulders. Improves focus and balance. Stretches the upper and lower back. Strengthens the abdominal muscles. Tones the abdominal area."},
  "Half-Moon":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483085/yoga-api/21_etedlp.png",t:"From a standing position one leg is straight while the other is extended back parallel to the earth (or a little above parallel) and one hand is on the earth (beyond the little-toe side of the foot, about 12 inches) while the other hand is extended up towards the sky. The shoulder blades are squeezed together and the fingers move outward in opposing directions. The weight of the body is supported mostly by the standing leg while the bottom hand has very little weight on it but is used intelligently to regulate balance. The upper torso is rotated open to the sky. Both hips are externally rotated. Energy is extended actively through the flexed toes to keep the raised leg strong. The inner ankle of the standing foot is lifted strongly upward, as if drawing energy from the earth. The sacrum and scapulae are firmly pressed against the back torso and lengthen the coccyx toward the raised foot. The gaze is either up or down, depending on the condition of the neck. If injured the gaze is down. Benefits: Strengthens the abdomen, ankles, thighs, buttocks and spine. Stretches the groins, hamstrings, calves, shoulders, chest and spine. Improves coordination and sense of balance. Helps relieve stress. Improves digestion."},
  "Handstand":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483085/yoga-api/22_ojzmr8.png",t:"In this inverted posture the weight of the body is on the hands - shoulder-width apart with fingers forward and parallel to each other (if the shoulders are tight, the index fingers are turned out slightly). The shoulder blades are firm against the back torso and pulled up toward the tailbone. The upper arms are rotated outward with the eye of the elbow to the front of the room to keep the shoulder blades broad while the outer arms hug inward in opposing forces for balance and stability. The palms are spread and the bases of the index fingers are pressed firmly against the earth. Balance is maintained by keeping the Bandhas engaged while pressing the earth away with straight arms and flexed feet. The gaze is down and forward. Benefits: Strengthens the shoulders, arms and wrists. Stretches the belly. Improves sense of balance. Calms the brain and helps relieve stress and mild depression."},
  "Low Lunge":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483086/yoga-api/23_k2jccj.png",t:"The front knee is bent in a 90-degree angle directly above the ankle and the back knee is resting on the earth with the top of the back foot pressed firmly into the earth. The hips are squared and pressed forward. The inner thighs scissor towards each other. The pelvis is tucked under to protect the low back. The ribcage is lifted. The arms are lifted. The hands can be together or separated and facing each other with the fingers spread wide. The gaze is forward. Benefits: Stretches the chest, lungs, neck, belly and groin (psoas). Strengthens the shoulders, arms and back muscles. Strengthens and stretches the thighs, calves and ankles."},
  "King Pigeon":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483087/yoga-api/25_rssro9.png",t:"From a seated position with the hips squared, one leg is extended forward with the knee bent and parallel to the earth. The front heel is rooted close to the groin (or extended out in a 90 degree angle if flexibility allows). The other leg is extended back with the knee bent and perpendicular to the earth. The back foot is hooked on the inside of the elbow of the back arm. The front elbow is bent upward perpendicular to the earth with the bicep by the ear. The fingers are interlaced to connect the bind behind the body and assist in opening the chest. The gaze is natural and forward. Benefits: Stretches the thighs, groins (psoas), abdomen, chest, shoulders and neck. Stimulates the abdominal organs. Opens the shoulders and chest."},
  "Plow":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483088/yoga-api/27_m4yux9.png",t:"From a supine position, the upper back rests on the earth with the hips and legs revolved back over the torso above and beyond the head towards the earth. The torso is perpendicular to the earth. The legs are fully extended with no bend at the knees as the toes reach for the earth. The hands are either supporting the lower back or extended behind the back on the earth with extended elbows and fingers interlaced (as flexibility allows), opening the shoulders. The neck is straight. The chin tucked. Do not look to the side as this may injure the neck. The is gaze inward. Benefits: Calms the brain. Stimulates the abdominal organs and the thyroid glands. Stretches the shoulders and spine. Helps relieve the symptoms of menopause. Reduces stress and fatigue. Therapeutic for backache, headache, infertility, insomnia, and sinusitis."},
  "Pyramid":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483089/yoga-api/28_uu58tt.png",t:"From a standing position with one leg forward and one back lean the torso forward at the crease of the hip joint. Stop when the torso is parallel to the floor. Press the fingertips or flat palms to the floor on either side of the front foot, maintaining a straight elongated spine. If it isn’t possible to touch the floor, or to maintain a straight spine, support the hands on a pair of blocks. Press the thighs back and lengthen the torso forward, lifting up through the top of the sternum. Then, as flexibility allows, bring the front torso closer to the top of the thigh without rounding the spine. Eventually the long front torso will rest down on the thigh. The gaze is down. Benefits: Calms the brain. Stretches the spine, the shoulders, the hips and the hamstrings. Strengthens the legs. Stimulates the abdominal organs. Improves posture and sense of balance. Improves digestion."},
  "Reverse Warrior":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483089/yoga-api/29_ww7bot.png",t:"From warrior II , the lower body stays static while the upper body arches back in a gentle back bend. The top arm is extended back with the bicep by the ear and the fingers spread wide. The other arm slides down the back leg resting on the thigh or shin, but not the knee joint. The gaze is up towards the sky. Benefits: Strengthens and stretches the legs, knees, and ankles. Stretches the groin, spine, waist, chest, lungs, and shoulders. Stimulates abdominal organs. Increases stamina. Relieves backaches, especially through second trimester of pregnancy. Therapeutic for carpal tunnel syndrome, flat feet, infertility, osteoporosis, and sciatica."},
  "Seated Forward Bend":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483091/yoga-api/30_gumpl3.png",t:"From a seated position with the sits bones rooted into the earth the legs extend forward to the degree that the chest and thighs can stay connected. The fingers wrap around the toes. The upper torso folds forward at the crease of the hips with the spine long. The gaze is forward. Benefits: Calms the brain and helps relieve stress and mild depression. Stretches the spine, shoulders and hamstrings. Stimulates the liver, kidneys, ovaries and uterus. Improves digestion. Helps relieve the symptoms of menopause and menstrual discomfort. Soothes headache and anxiety. Reduces fatigue. Therapeutic for high blood pressure, infertility, insomnia and sinusitis. Traditional texts say that Paschimottanasana increases appetite, reduces obesity and cures diseases."},
  "Lotus":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483091/yoga-api/31_ozseum.png",t:"Bring the bottom ankle and place it on top of the opposite knee, both ankles will be resting on top of the thighs. Benefits: Opens the hips, groin and stretches the knees, ankles and thighs. Strengthens the back and calms the mind, reduces stress and anxiety. Improves circulation and blood flow in the pelvis."},
  "Half Lord of the Fishes":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483091/yoga-api/32_hafoa0.png",t:"Begin in a seated position. Bend one knee so the sole of your foot is close to the opposite inner thigh. Bend your opposite knee in, foot on the floor, heel to the outside of your bent thigh. Extend your arm (same side of your Lotus leg) high into the sky and begin to twist it to the outside of your bent knee. Use your opposite hand as leverage to twist deeper. Hook your elbow to the outside of your thigh and gaze over your back shoulder. If you want to extend your twist deeper, wrap your arm around the shin of your bent knee and sweep your opposite arm around to meet it. Catch opposite fingertips or the wrist. Keep a long spine. Benefits: Stretches the shoulders, the chest, the thighs, the groins, and the abdomen. Strengthens the legs and the ankles. Improves balance."},
  "Shoulder Stand":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483091/yoga-api/33_r7motl.png",t:"From a supine position, the upper back is resting on the earth with the hips straight up towards the sky. The torso is perpendicular to the earth. The legs are fully extended and the toes are active. The hands are either supporting the lower back or extended up by the side body in matchstick. The neck is flat on the earth and the chin is tucked in. The gaze is inward. Benefits: Calms the brain and helps relieve stress and mild depression. Stimulates the thyroid and prostate glands and abdominal organs. Stretches the shoulders and neck. Tones the legs and buttocks. Improves digestion. Helps relieve the symptoms of menopause. Reduces fatigue and alleviates insomnia. Therapeutic for asthma, infertility, and sinusitis."},
  "Sphinx":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483092/yoga-api/35_dytwvz.png",t:"From a prone position with the pelvic bowl is firmly contracted interiorly towards the center line of the body while the pubis is tucked under. The legs are extended back and the tops of the feet are flat. The palms are flat and the elbows are on the mat, stacked right below the shoulders. On an inhalation, lift the sternum and extend the neck away from shoulders with the elbows, palms and pelvic bone firmly attached to the mat. Benefits: Strengthens the spine. Stretches the chest, the lungs, the shoulders and the abdomen. Stimulates the abdominal organs. Opens the heart and the lungs."},
  "Splits":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483092/yoga-api/36_a2z20a.png",t:"The hips are parallel and squared to the earth with one leg extended forward. The opposite leg extended back with the knee and foot squared to the earth. The inner thighs scissor towards each other. The hands are by the side body or at the heart center in Anjali Mudra (Salutation Seal) or stretched straight up toward the sky. The ribcage is lifted. The heart is open. The gaze is forward. Benefits: Stretches the thighs, hamstrings, and groin. Stimulates the abdominal organs."},
  "Garland Pose":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483093/yoga-api/37_moh7ii.png",t:"From a squatting position the feet are as close together as possible (keep your heels on the floor if you can; otherwise, support them on a folded mat). The thighs are slightly wider than the torso. The torso is leaning gently forward and tucked snugly between the thighs. The elbows are pressed against the inner knees and the palms are together in Anjali Mudra (Salutation Seal). The knees resist the elbows to help lengthen the front torso. The gaze is soft and forward. Benefits: Stretches the ankles, groins and back torso. Tones the belly."},
  "Standing Forward Bend":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483093/yoga-api/38_yb3thk.png",t:"From a standing position, the body is folded over at the crease of the hip with the spine long. The neck is relaxed and the crown of the head is towards the earth. The feet are rooted into the earth with the toes actively lifted. The spine is straight. The ribcage is lifted. The chest and the thighs are connected. The sacrum lifts up toward the sky in dog tilt. The fingertips are resting on the earth next to the toes. The gaze is down or slightly forward. Benefits: Calms the brain and helps relieve stress and mild depression. Stimulates the liver and kidneys. Stretches the hamstrings, calves, and hips. Strengthens the thighs and knees. Improves digestion. Helps relieve the symptoms of menopause. Reduces fatigue and anxiety. Relieves headache and insomnia."},
  "Crescent Moon":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483095/yoga-api/39_hqj0sa.png",t:"From mountain pose, on the inhalation bring the hands up and interlace the fingers together. Exhale, bend to one side, lengthening the opposite of the rib cage and stretch. Benefits: Stretches the rib cage, arms and torso. Tones the oblique muscles."},
  "Side Splits":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483093/yoga-api/40_dkmow6.png",t:"From a wide stance the legs are open and extended sideways to your degree of flexibility. The outer edges of the feet are rotated and gripping toward the earth. The weight of the body is supported by the arms. The palms are rooted into the earth with the fingers pointing towards the body. There should be no excess weight on the knee or ankle joints as you lower down to your degree of flexibility. The gaze is down and slightly forward. Benefits: Stretches the insides and backs of the legs. Stimulates the abdominal organs. Strengthens the spine. Calms the brain. Releases groin."},
  "Triangle":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483096/yoga-api/42_jawxqw.png",t:"From a standing position, the legs are straight and separated into a wide stance. The feet are aligned and flat on the earth with the back foot in a 60-degree angle towards the front. The inner thighs are rotated externally away from each other. The pelvis is tucked and the ribcage is lifted. One arm extends up towards the sky as the other reaches down to the earth. Both arms are aligned with the shoulders in a straight line. The fingers reach out as the shoulder blades squeeze together. The gaze is toward the front. Benefits: Stretches and strengthens the thighs, knees, and ankles. Stretches the hips, groin, hamstrings, calves, shoulders, chest, and spine. Stimulates the abdominal organs. Helps relieve stress. Improves digestion. Helps relieve the symptoms of menopause. Relieves backache, especially through second trimester of pregnancy. Therapeutic for anxiety, flat feet, infertility, neck pain, osteoporosis, and sciatica."},
  "Upward-Facing Dog":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483096/yoga-api/43_m3nxjk.png",t:"The body is in a prone position parallel to the earth. The weight of the body is supported equally by the straight arms and the tops of the feet which press firmly into the earth. The shoulders are rotated back and down. The ribcage is lifted and pulled thru to the front in a slight upper thoracic backbend. The joints are stacked with the wrists, elbows and shoulders in a straight-line. The neck is a natural extension of the spine and the chin is slightly tucked. The abdomen is pulled up towards the spine. The palms are flat and the elbows are close to the side body. The gaze is forward. Benefits: Improves posture. Strengthens the spine, arms, and wrists. Stretches the chest, lungs, shoulders, and abdomen. Firms the buttocks. Stimulates abdominal organs. Helps relieve mild depression, fatigue, and sciatica. Therapeutic for asthma."},
  "Warrior One":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483096/yoga-api/44_dqeayo.png",t:"From a standing position, the legs are in a wide stance with the feet aligned and flat on the earth. The back foot is in a 60-degree angle towards the front. The hips are squared. The inner thighs are rotated towards each other. The front knee is bent in a 90-degree angle directly above the ankle. The arms extend up to the sky with the biceps by the ears. The hands can be together or separated and facing each other with the fingers spread wide. The ribcage is lifted and the pelvis tucked. The gaze is forward. Benefits: Stretches the chest, lungs, shoulders, neck, belly and groin (psoas). Strengthens the shoulders, arms and back muscles. Strengthens and stretches the thighs, calves and ankles."},
  "Warrior Three":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483097/yoga-api/46_lz6v7i.png",t:"From a standing position, one leg is rooted and perpendicular to the earth while the other leg is raised, extended back and parallel to the earth. The head of the thighbone of the standing leg presses back towards the heel and is actively rooted into the earth. The arms and the extended leg lengthen in opposing directions with Bandhas engaged. The hips are squared and the tailbone presses firmly into the pelvis. The arms, torso, and extended raised leg should be positioned relatively parallel to the floor. The gaze is forward or down. Benefits: Strengthens the ankles and legs. Strengthens the shoulders and muscles of the back. Tones the abdomen. Improves balance and posture."},
  "Wheel":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483097/yoga-api/47_w2jsof.png",t:"Pressed up from a supine position, lying on your back, the palms are rooted into the earth with the fingers pointed towards the heels. The feet are grounded. The hips are pressed up. The thighs are rotated inward. The thoracic spine is arched creating a strong crescent arch along the spinal column. The gaze is forward. Benefits: Strengthens the arms, wrists, legs, buttocks, abs, and spine. Stimulates the thyroid and pituitary. Increases energy and counteracts depression. Therapeutic for asthma, back pain, infertility, and osteoporosis."},
  "Wild Thing":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483097/yoga-api/48_unoav6.png",t:"From downward dog pose, elevate one leg toward the sky and stack the corresponding hip over the other hip. Bring the upper heel as close to the buttocks as possible. The hips remain stacked; then bring the shoulders forward slowly over the hands. Replace the corresponding hand to the upraised leg with the other hand and flip yourself over and extend the top hand forward. The bottom foot is now facing toward the front of the mat and you remain on the ball of the top foot and the corresponding knee is bent. Continue to lift hips up towards the sky and continue reaching the free hand towards the front of the room and slightly downwards. Allow the head to curl back. Benefits: Stretches the chest, shoulders, back, and throat. Strengthens and opens the hips, hip flexors, and thighs."},
  "Downward Dog":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483081/yoga-api/15_vkviqn.png",t:"From downward-facing dog the legs are straight with the sits bones tilted up and reaching for the sky. The feet are flat with the heels firmly rooted. One palm is flat with the knuckles evenly pressed into the earth. The other hand reaches under the body and grasps the opposite ankle. The spine is long and the heart is open toward the sky. The neck is loose and the crown of the head is relaxed toward the earth. The gaze is toward the center. Benefits: Calms the brain and helps relieve stress and mild depression. Energizes the body. Stretches the shoulders, neck, hamstrings, calves, arches, and hands. Strengthens the arms and legs. Helps relieve the symptoms of menopause. Relieves menstrual discomfort when done with the head supported. Helps prevent osteoporosis. Improves digestion. Relieves headache, insomnia, back pain, and fatigue. Therapeutic for high blood pressure, asthma, flat feet, sciatica, and sinusitis."},
  "Pigeon Pose":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483088/yoga-api/24_ulgsjo.png",t:"Lie on the back in supine position. Bend the knees, heels close to SI bones and cross one ankle over the opposite knee. Thread the hands or reach through between the thighs. Lift the foot off the floor and hold the bent knee behind the thigh or shin to bring it closer to the chest, make sure that the acrum is rooted to the floor. Benefits: Stretches the hamstrings and quads. If the elbow is used to push the thigh, it opens the hips as well."},
  "Warrior II":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483096/yoga-api/45_ehimr1.png",t:"From a standing position, the legs are separated into a wide stance. The front knee is bent in a 90-degree angle directly above the ankle. The back leg is extended and straight with the outside edge of the back foot gripping the earth in a 60-degree angle towards the front. The inner thighs are externally rotated away from each other. The pelvis is tucked. The ribcage is lifted. The arms are extended out to the sides and are aligned with the shoulders in a straight line with the fingers reaching out as the shoulder blades squeeze together. The gaze is toward the front fingers. Benefits: Strengthens and stretches the legs and ankles. Stretches the groin, chest, lungs, and shoulders. Stimulates abdominal organs. Increases stamina. Relieves backaches, especially through second trimester of pregnancy. Therapeutic for carpal tunnel syndrome, flat feet, infertility, osteoporosis, and sciatica."},
  "Tree Pose":{img:"https://res.cloudinary.com/dko1be2jy/image/upload/fl_sanitize/v1676483094/yoga-api/41_veknug.png",t:"From a standing position, one foot is rooted into the earth with the opposite heel rooted into the inner thigh with the toes pointing towards the earth. The pelvis and the chin are tucked in. The arms are lifted above the head with the palms together in prayer position. The gaze is forward. Benefits: Strengthens the legs, ankles, and feet. Improves flexibility in the hips and knees. Improves balance."}
};
const FEDB_IMG = "https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/";
const EXMEDIA = {};   /* name -> {img,vid,page} | "none" | "err" */
const EXPENDING = {};
function loadExMedia(name){
  if(EXMEDIA[name]) return Promise.resolve(EXMEDIA[name]);
  if(EXPENDING[name]) return EXPENDING[name];
  return EXPENDING[name] = _loadExMedia(name).finally(()=>{ delete EXPENDING[name]; });
}
async function _loadExMedia(name){
  if(EXMEDIA[name]) return EXMEDIA[name];
  const gc = GC[name];
  if(!gc) return EXMEDIA[name] = "none";
  try{
    const r = await fetch(GC_DATA + gc + ".json");
    if(r.status === 404 || r.status === 403) return EXMEDIA[name] = "none";
    const d = await r.json();
    const v = d.videos?.[0];
    EXMEDIA[name] = {
      img: v ? GC_VID + v.thumbnail : (d.heroImage ? "https://connect.garmin.com" + d.heroImage : null),
      vid: v ? GC_VID + v.video : null,
      page: GC_PAGE + gc
    };
    if(!EXMEDIA[name].img) EXMEDIA[name] = "err";
  }catch(e){ EXMEDIA[name] = "err"; }
  return EXMEDIA[name];
}
